func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    let totalNodes = Int(n)
    let kInt = Int(k)

    if edges.isEmpty {
        if kInt <= totalNodes {
            return 0
        } else {
            return -1
        }
    }

    let maxEdgeTime = edges.max { a, b in a[2] < b[2] }?[2] ?? 0
    var low: Int64 = 0
    var high: Int64 = maxEdgeTime + 1

    while low < high {
        let mid = (low + high) / 2
        let compCount = countComponents(n: totalNodes, edges: edges, t: mid)
        if compCount >= kInt {
            high = mid
        } else {
            low = mid + 1
        }
    }

    return low
}

func countComponents(n: Int, edges: Array<Array<Int64>>, t: Int64) -> Int {
    var graph = [[Int]](repeating: [Int](), count: n)
    for edge in edges {
        let u = Int(edge[0])
        let v = Int(edge[1])
        let time = edge[2]
        if time > t {
            graph[u].append(v)
            graph[v].append(u)
        }
    }

    var visited = [Bool](repeating: false, count: n)
    var compCount = 0
    for i in 0..<n {
        if !visited[i] {
            compCount += 1
            var queue = [Int]()
            var index = 0
            queue.append(i)
            visited[i] = true
            while index < queue.count {
                let node = queue[index]
                index += 1
                for neighbor in graph[node] {
                    if !visited[neighbor] {
                        visited[neighbor] = true
                        queue.append(neighbor)
                    }
                }
            }
        }
    }
    return compCount
}
```

### Explanation
1. **Binary Search Setup**: The binary search is initialized with `low` set to 0 and `high` set to the maximum edge time + 1. This ensures the search covers all possible times where edges could be removed.
2. **Graph Construction**: For each midpoint time `mid` during the binary search, the graph is constructed by including edges that have a removal time strictly greater than `mid`. This simulates the state of the graph after removing edges at or before `mid`.
3. **Component Counting**: Using BFS, the number of connected components in the graph is counted. The BFS starts from each unvisited node, marking all reachable nodes as visited and incrementing the component count for each new component found.
4. **Binary Search Adjustment**: The binary search adjusts its bounds based on whether the current component count meets or exceeds `k`. If it does, the search continues in the lower half to find a smaller `t`; otherwise, it searches the upper half.
5. **Result Extraction**: The loop exits when `low` equals `high`, which is the minimal `t` ensuring the graph splits into at least `k` components. This value is returned as the solution.

This approach efficiently narrows down the minimal time `t` using binary search and BFS, ensuring optimal performance even for large input sizes.

To solve this problem, we need to find the minimal time `t` such that after removing all edges with removal time less than or equal to `t`, the graph has at least `k` connected components. The solution involves using binary search on the possible values of `t` to efficiently determine the smallest `t` that satisfies the condition.

### Approach
1. **Binary Search Setup**: The binary search is performed over the range `[0, max_time + 1]`, where `max_time` is the maximum removal time among all edges. This range ensures we cover all possible values of `t`.
2. **Helper Function**: For each candidate `t` during the binary search, we compute the number of connected components in the graph after removing edges with removal time `<= t`. This is done using a Union-Find (Disjoint Set Union, DSU) data structure:
   - **Initialization**: Start with each node as its own parent and rank 0.
   - **Union-Find Operations**: Process each edge with removal time `> t`. For each such edge, perform a union operation on the nodes it connects. Path compression and union by rank are used to optimize the operations.
   - **Component Count**: The number of connected components is tracked by decrementing a counter whenever two distinct components are merged.
3. **Binary Search Execution**: Adjust the binary search bounds based on whether the current `t` yields at least `k` components. If it does, we search for a smaller `t`; otherwise, we search for a larger `t`.

### Solution Code
```swift
func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    let nInt = Int(n)
    let kInt = Int(k)
    var max_t: Int64 = 0
    for edge in edges {
        if edge[2] > max_t {
            max_t = edge[2]
        }
    }

    func components(atTime t: Int64) -> Int {
        var parent = Array(0..<nInt)
        var rank = [Int](repeating: 0, count: nInt)
        var comp_count = nInt

        func find(_ x: Int) -> Int {
            var stack = [Int]()
            var cur = x
            while parent[cur] != cur {
                stack.append(cur)
                cur = parent[cur]
            }
            let root = cur
            for node in stack {
                parent[node] = root
            }
            return root
        }

        for edge in edges {
            let time_val = edge[2]
            if time_val > t {
                let u = Int(edge[0])
                let v = Int(edge[1])
                let ru = find(u)
                let rv = find(v)
                if ru == rv {
                    continue
                }
                if rank[ru] < rank[rv] {
                    parent[ru] = rv
                } else if rank[ru] > rank[rv] {
                    parent[rv] = ru
                } else {
                    parent[rv] = ru
                    rank[ru] += 1
                }
                comp_count -= 1
            }
        }
        return comp_count
    }

    var low: Int64 = 0
    var high: Int64 = max_t + 1
    while low < high {
        let mid = low + (high - low) / 2
        if components(atTime: mid) >= kInt {
            high = mid
        } else {
            low = mid + 1
        }
    }
    return low
}
```

### Explanation
1. **Binary Search**: The binary search efficiently narrows down the minimal `t` by checking mid-values in the range `[0, max_time + 1]`.
2. **DSU for Component Count**: For each `t`, the `components(atTime:)` function initializes each node as its own component. It processes edges with removal time `> t`, using the `find` function with path compression to locate the root of each node and the `union` operation to merge components. The number of components is updated whenever two distinct components are merged.
3. **Efficiency**: The binary search runs in logarithmic time relative to the maximum edge removal time, and each DSU operation is nearly constant time due to path compression and union by rank. This makes the solution efficient even for large inputs. The overall complexity is approximately \(O(\text{max\_time\_log} \times E \times \alpha(n))\), where \(\alpha(n)\) is the inverse Ackermann function, effectively constant for practical purposes.
